class OAuth2Client {
  constructor(config) {
    this.clientId = config.clientId;
    this.clientSecret = config.clientSecret;
    this.redirectUri = config.redirectUri;
    this.authorizationEndpoint = config.authorizationEndpoint;
    this.tokenEndpoint = config.tokenEndpoint;
    this.scopes = config.scopes || ['read'];
  }

  async getAuthorizationUrl() {
    const params = new URLSearchParams({
      response_type: 'code',
      client_id: this.clientId,
      redirect_uri: this.redirectUri,
      scope: this.scopes.join(' '),
      state: this.generateState(),
    });
    return `${this.authorizationEndpoint}?${params.toString()}`;
  }

  generateState() {
    return Math.random().toString(36).substring(2, 15) + 
           Math.random().toString(36).substring(2, 15);
  }

  async handleCallback(url) {
    const urlObj = new URL(url);
    const code = urlObj.searchParams.get('code');
    const state = urlObj.searchParams.get('state');
    const error = urlObj.searchParams.get('error');

    if (error) {
      throw new Error(`OAuth error: ${error}`);
    }

    if (!code) {
      throw new Error('No authorization code received');
    }

    const tokenData = await this.exchangeCodeForToken(code);
    this.storeTokens(tokenData);
    return tokenData;
  }

  async exchangeCodeForToken(code) {
    const response = await fetch(this.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': 'Basic ' + btoa(`${this.clientId}:${this.clientSecret}`)
      },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: this.redirectUri,
      }).toString()
    });

    if (!response.ok) {
      throw new Error(`Token exchange failed: ${response.status}`);
    }

    return await response.json();
  }

  storeTokens(tokens) {
    localStorage.setItem('oauth_tokens', JSON.stringify(tokens));
  }

  getTokens() {
    const tokens = localStorage.getItem('oauth_tokens');
    return tokens ? JSON.parse(tokens) : null;
  }

  async refreshAccessToken() {
    const tokens = this.getTokens();
    if (!tokens || !tokens.refresh_token) {
      throw new Error('No refresh token available');
    }

    const response = await fetch(this.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': 'Basic ' + btoa(`${this.clientId}:${this.clientSecret}`)
      },
      body: new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: tokens.refresh_token,
      }).toString()
    });

    if (!response.ok) {
      throw new Error(`Token refresh failed: ${response.status}`);
    }

    const newTokens = await response.json();
    this.storeTokens(newTokens);
    return newTokens;
  }

  async makeAuthenticatedRequest(url, options = {}) {
    const tokens = this.getTokens();
    if (!tokens || !tokens.access_token) {
      throw new Error('No access token available');
    }

    const defaultOptions = {
      headers: {
        'Authorization': `Bearer ${tokens.access_token}`,
        'Content-Type': 'application/json',
      }
    };

    const finalOptions = { ...defaultOptions, ...options };

    try {
      const response = await fetch(url, finalOptions);
      
      if (response.status === 401) {
        // Token might be expired, try to refresh
        const newTokens = await this.refreshAccessToken();
        finalOptions.headers.Authorization = `Bearer ${newTokens.access_token}`;
        return await fetch(url, finalOptions);
      }

      return response;
    } catch (error) {
      throw new Error(`API request failed: ${error.message}`);
    }
  }

  logout() {
    localStorage.removeItem('oauth_tokens');
  }
}

// Usage example in React component
const useOAuth = () => {
  const [tokens, setTokens] = useState(null);
  const [isLoading, setIsLoading] = useState(false);
  const oauthClient = new OAuth2Client({
    clientId: process.env.REACT_APP_OAUTH_CLIENT_ID,
    clientSecret: process.env.REACT_APP_OAUTH_CLIENT_SECRET,
    redirectUri: process.env.REACT_APP_OAUTH_REDIRECT_URI,
    authorizationEndpoint: process.env.REACT_APP_OAUTH_AUTHORIZATION_ENDPOINT,
    tokenEndpoint: process.env.REACT_APP_OAUTH_TOKEN_ENDPOINT,
    scopes: ['read', 'write']
  });

  useEffect(() => {
    const storedTokens = oauthClient.getTokens();
    if (storedTokens) {
      setTokens(storedTokens);
    }
  }, []);

  const login = async () => {
    try {
      const authUrl = await oauthClient.getAuthorizationUrl();
      window.location.href = authUrl;
    } catch (error) {
      console.error('Login failed:', error);
    }
  };

  const handleCallback = async (url) => {
    setIsLoading(true);
    try {
      const tokens = await oauthClient.handleCallback(url);
      setTokens(tokens);
    } catch (error) {
      console.error('Callback handling failed:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const apiRequest = async (url, options = {}) => {
    try {
      const response = await oauthClient.makeAuthenticatedRequest(url, options);
      return await response.json();
    } catch (error) {
      throw error;
    }
  };

  const logout = () => {
    oauthClient.logout();
    setTokens(null);
  };

  return {
    tokens,
    isLoading,
    login,
    handleCallback,
    apiRequest,
    logout
  };
};